local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxWatchTowerCtrl:LxBaseCtrl
local LxWatchTowerCtrl = classX("LxWatchTowerCtrl", LxBaseCtrl)

function LxWatchTowerCtrl:Initialize()
    LxBaseCtrl.Initialize(self)
    self._isInitCheck = true
end

function LxWatchTowerCtrl:Dispose()
    LxBaseCtrl.Dispose(self)
end

--- 红点规则
--- 每次重新登录时：显示已完成未领取+未完成的数量。在打开灯塔界面后扣除未完成的数量，已完成的数量需要常驻显示直到领取完成；未完成数量不包括类型7
function LxWatchTowerCtrl:CheckRed()
    local wtModule = ModuleCenter.WatchTower
    local eventList = wtModule:GetEventMap()
    --local curTime = wtModule:GetNextRefreshTime()
    --local oldTime = wtModule:GetOldRefreshTime()
    local refList = GameTable.WatchTowerEventRef
    local redNum = 0
    --if curTime > oldTime then
    --    return true
    --end
    for i, v in pairs(eventList) do
        local ref = refList[v.refId]
        if self._isInitCheck then
            if ref.eventTypeId ~= WatchTowerEventType.PirateBoss then
                redNum = redNum + 1
            elseif ref.eventTypeId == WatchTowerEventType.PirateBoss and v.status == WatchTowerState.CanGet then
                redNum = redNum + 1
            end
        else
            if v.status == WatchTowerState.CanGet then
                redNum = redNum + 1
            end
        end
    end
    return redNum
end
function LxWatchTowerCtrl:SetInitCheck()
    self._isInitCheck = false
end
return LxWatchTowerCtrl